import React, { useState, useEffect } from "react";
import { MatchState, Player, Recommendation } from "../types";
import * as api from "../api";
import { MatchSetup } from "../components/MatchSetup";
import { TeamRoster } from "../components/TeamRoster";
import { LegalPlayersPanel } from "../components/LegalPlayersPanel";
import { RecommendationPanel } from "../components/RecommendationPanel";
import { OpponentPickPanel } from "../components/OpponentPickPanel";
import { RoundTracker } from "../components/RoundTracker";
import { MatchupHistory } from "../components/MatchupHistory";
import { MatchupSelector } from "../components/MatchupSelector";
import { CaptainGuidancePanel } from "../components/CaptainGuidancePanel";

export const Dashboard: React.FC = () => {
  const [matchState, setMatchState] = useState<MatchState | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [ourLegalPlayers, setOurLegalPlayers] = useState<Player[]>([]);
  const [oppLegalPlayers, setOppLegalPlayers] = useState<Player[]>([]);
  const [firstDeclRecommendations, setFirstDeclRecommendations] = useState<Recommendation[]>([]);
  const [responseRecommendations, setResponseRecommendations] = useState<Recommendation[]>([]);
  const [selectedOppId, setSelectedOppId] = useState<string | null>(null);

  // Selection state for matchup locking
  const [selectedOurPlayer, setSelectedOurPlayer] = useState<Player | null>(null);
  const [selectedOppPlayer, setSelectedOppPlayer] = useState<Player | null>(null);

  const isMatchComplete = matchState ? matchState.round_index > 5 : false;
  const currentDeclarer = matchState 
    ? matchState.first_declarer_by_round[matchState.round_index - 1] || "us"
    : "us";

  const loadSampleMatch = async () => {
    setIsLoading(true);
    setError(null);
    try {
      const data = await api.getSampleMatch();
      const state: MatchState = {
        format: data.format,
        round_index: data.round_index,
        our_team: data.our_team,
        opp_team: data.opp_team,
        our_used_player_ids: data.our_used_player_ids || [],
        opp_used_player_ids: data.opp_used_player_ids || [],
        our_points: data.our_points || 0,
        opp_points: data.opp_points || 0,
        first_declarer_by_round: data.first_declarer_by_round || ["us", "opp", "us", "opp", "us"],
        locked_matchups: data.locked_matchups || [],
      };
      setMatchState(state);
      setFirstDeclRecommendations([]);
      setResponseRecommendations([]);
      setSelectedOppId(null);
      setSelectedOurPlayer(null);
      setSelectedOppPlayer(null);

      // Load legal players
      const legalData = await api.getLegalPlayers(state);
      setOurLegalPlayers(legalData.our_legal_players || []);
      setOppLegalPlayers(legalData.opp_legal_players || []);
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to load match");
    } finally {
      setIsLoading(false);
    }
  };

  const refreshLegalPlayers = async () => {
    if (!matchState) return;
    try {
      const legalData = await api.getLegalPlayers(matchState);
      setOurLegalPlayers(legalData.our_legal_players || []);
      setOppLegalPlayers(legalData.opp_legal_players || []);
    } catch (err) {
      console.error("Failed to refresh legal players:", err);
    }
  };

  const handleBestFirstDeclaration = async () => {
    if (!matchState) return;
    setIsLoading(true);
    setError(null);
    try {
      const data = await api.getBestFirstDeclaration(matchState);
      setFirstDeclRecommendations(data.recommendations || []);
      setResponseRecommendations([]);
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to get recommendations");
    } finally {
      setIsLoading(false);
    }
  };

  const handleBestResponse = async () => {
    if (!matchState || !selectedOppId) return;
    setIsLoading(true);
    setError(null);
    try {
      const data = await api.getBestResponse(matchState, selectedOppId);
      setResponseRecommendations(data.recommendations || []);
      setFirstDeclRecommendations([]);
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to get recommendations");
    } finally {
      setIsLoading(false);
    }
  };

  const handleSelectFromRecommendation = (rec: Recommendation, isOpp: boolean) => {
    const player = rec.player as unknown as Player;
    if (isOpp) {
      setSelectedOppPlayer(player);
      setSelectedOppId(player.id);
    } else {
      setSelectedOurPlayer(player);
    }
  };

  const handleLockMatchup = async () => {
    if (!matchState || !selectedOurPlayer || !selectedOppPlayer) return;
    setIsLoading(true);
    setError(null);
    try {
      const result = await api.applyMatchup(
        matchState,
        selectedOurPlayer.id,
        selectedOppPlayer.id
      );

      if (result.error) {
        setError(result.error);
        return;
      }

      const newState = result.state;
      setMatchState(newState);

      // Clear selections
      setSelectedOurPlayer(null);
      setSelectedOppPlayer(null);
      setSelectedOppId(null);
      setFirstDeclRecommendations([]);
      setResponseRecommendations([]);

      // Refresh legal players
      const legalData = await api.getLegalPlayers(newState);
      setOurLegalPlayers(legalData.our_legal_players || []);
      setOppLegalPlayers(legalData.opp_legal_players || []);
    } catch (err) {
      setError(err instanceof Error ? err.message : "Failed to lock matchup");
    } finally {
      setIsLoading(false);
    }
  };

  const getAvailableOppPlayers = (): Player[] => {
    if (!matchState) return [];
    return matchState.opp_team.players.filter(
      (p) => !matchState.opp_used_player_ids.includes(p.id)
    );
  };

  const canLockMatchup = !!(selectedOurPlayer && selectedOppPlayer && !isLoading);

  if (error) {
    return (
      <div style={styles.errorContainer}>
        <p style={styles.error}>Error: {error}</p>
        <button onClick={() => setError(null)} style={styles.errorButton}>
          Dismiss
        </button>
      </div>
    );
  }

  return (
    <div style={styles.container}>
      <header style={styles.header}>
        <h1 style={styles.headerTitle}>APA Pool Matchup Optimizer</h1>
        {matchState && (
          <button 
            onClick={loadSampleMatch} 
            style={styles.reloadButton}
          >
            Reload Sample Match
          </button>
        )}
      </header>

      <MatchSetup
        onLoadSample={loadSampleMatch}
        isLoading={isLoading}
        hasMatch={!!matchState}
      />

      {matchState && (
        <>
          {isMatchComplete && (
            <div style={styles.matchComplete}>
              <h2>🎉 Match Complete!</h2>
              <p>Final Score: Us {matchState.our_points.toFixed(1)} - {matchState.opp_points.toFixed(1)} Them</p>
            </div>
          )}

          <CaptainGuidancePanel matchState={matchState} />

          <RoundTracker matchState={matchState} />

          <div style={styles.grid}>
            <TeamRoster
              team={matchState.our_team}
              teamName="Our Team"
              usedPlayerIds={matchState.our_used_player_ids}
              legalPlayerIds={ourLegalPlayers.map((p) => p.id)}
              highlightIds={selectedOurPlayer ? [selectedOurPlayer.id] : []}
            />
            <TeamRoster
              team={matchState.opp_team}
              teamName="Opponent"
              usedPlayerIds={matchState.opp_used_player_ids}
              legalPlayerIds={oppLegalPlayers.map((p) => p.id)}
              highlightIds={selectedOppPlayer ? [selectedOppPlayer.id] : []}
            />
          </div>

          <LegalPlayersPanel
            ourPlayers={ourLegalPlayers}
            oppPlayers={oppLegalPlayers}
          />

          <MatchupHistory matchState={matchState} />

          <div style={styles.actionSection}>
            <div style={styles.actionCol}>
              {!isMatchComplete && (
                <button
                  style={styles.primaryButton}
                  onClick={handleBestFirstDeclaration}
                  disabled={isLoading}
                >
                  {isLoading ? "Loading..." : "Get Best First Declaration"}
                </button>
              )}

              {firstDeclRecommendations.length > 0 && !isMatchComplete && (
                <div style={styles.recSection}>
                  <RecommendationPanel
                    title="Best First - Select Our Player"
                    recommendations={firstDeclRecommendations as any}
                    onSelectPlayer={(rec) => handleSelectFromRecommendation(rec, false)}
                    selectedPlayerId={selectedOurPlayer?.id}
                  />
                  <div style={styles.useButtons}>
                    {firstDeclRecommendations.slice(0, 3).map((rec) => (
                      <button
                        key={rec.player.id}
                        style={{
                          ...styles.useButton,
                          backgroundColor: selectedOurPlayer?.id === rec.player.id ? "#28a745" : "#007bff",
                        }}
                        onClick={() => handleSelectFromRecommendation(rec, false)}
                      >
                        Use {rec.player.name}
                      </button>
                    ))}
                  </div>
                </div>
              )}
            </div>

            <div style={styles.actionCol}>
              {!isMatchComplete && (
                <OpponentPickPanel
                  availableOpponents={getAvailableOppPlayers()}
                  selectedOpponentId={selectedOppId}
                  onSelectOpponent={(id) => {
                    setSelectedOppId(id);
                    const player = getAvailableOppPlayers().find(p => p.id === id);
                    if (player) setSelectedOppPlayer(player);
                  }}
                  onRecommend={handleBestResponse}
                  isLoading={isLoading}
                />
              )}

              {responseRecommendations.length > 0 && !isMatchComplete && (
                <div style={styles.recSection}>
                  <RecommendationPanel
                    title="Best Response - Select Our Player"
                    recommendations={responseRecommendations as any}
                    onSelectPlayer={(rec) => handleSelectFromRecommendation(rec, false)}
                    selectedPlayerId={selectedOurPlayer?.id}
                  />
                  <div style={styles.useButtons}>
                    {responseRecommendations.slice(0, 3).map((rec) => (
                      <button
                        key={rec.player.id}
                        style={{
                          ...styles.useButton,
                          backgroundColor: selectedOurPlayer?.id === rec.player.id ? "#28a745" : "#007bff",
                        }}
                        onClick={() => handleSelectFromRecommendation(rec, false)}
                      >
                        Use {rec.player.name}
                      </button>
                    ))}
                  </div>
                </div>
              )}
            </div>
          </div>

          {!isMatchComplete && (
            <MatchupSelector
              ourPlayer={selectedOurPlayer}
              oppPlayer={selectedOppPlayer}
              ourOptions={ourLegalPlayers}
              oppOptions={getAvailableOppPlayers()}
              onOurSelect={setSelectedOurPlayer}
              onOppSelect={setSelectedOppPlayer}
              onLock={handleLockMatchup}
              canLock={canLockMatchup}
              isLoading={isLoading}
              currentDeclarer={currentDeclarer}
            />
          )}
        </>
      )}
    </div>
  );
};

